sql:
SELECT * 
FROM speed_records 
WHERE avg_speed < 60;

external_knowledge:
- 'Low-maintenance plants in a garden' is a metaphor for sensors that require fewer maintenance services; 
- 'First serviced' and 'last service' refer to the earliest and latest maintenance dates of the sensors;
- 'How many times have they been serviced overall' refers to the count of maintenance records for each sensor, which is the maintenance frequency.

- 'struggling under the weight of neglect and disrepair' refers to roads with 'poor' surface quality and 'overdue' maintenance status;
- 'reduced to a crawl' refers to a lower average speed;
- 'most sluggish to the least' means ranking by average speed from lowest to highest;
- 'from the most perilous to the safest' ranking by number of incidents from highest to lowest.

sql:
SELECT incident_id, incident_type, start_time, end_time
FROM traffic_incidents
WHERE start_time BETWEEN 'Start Date' AND 'End Date';

SELECT ref_speed_id_day_week, ref_speed_id_day_week_hour_day, dif_speed_id_day_week
FROM speed_records
ORDER BY speed_id DESC;
